const express = require('express');
const app = express();
app.use(express.json());

// In-memory data
let users = [];
let posts = [];
let comments = [];
let nextId = 1;

// Users routes
app.get('/api/users', (req, res) => {
  res.json(users);
});

app.post('/api/users', (req, res) => {
  const { name, email } = req.body;
  if (!name || !email) {
    return res.status(400).json({ error: 'Name and email are required' });
  }

  const user = { id: nextId++, name, email, createdAt: new Date() };
  users.push(user);
  res.status(201).json(user);
});

app.get('/api/users/:id', (req, res) => {
  const user = users.find(u => u.id === parseInt(req.params.id));
  if (!user) {
    return res.status(404).json({ error: 'User not found' });
  }
  res.json(user);
});

// Posts routes
app.get('/api/posts', (req, res) => {
  const { authorId, page = 1, limit = 10 } = req.query;
  let filteredPosts = posts;

  if (authorId) {
    filteredPosts = posts.filter(p => p.authorId === parseInt(authorId));
  }

  // Pagination
  const startIndex = (page - 1) * limit;
  const paginatedPosts = filteredPosts.slice(startIndex, startIndex + parseInt(limit));

  res.json({
    data: paginatedPosts,
    pagination: {
      total: filteredPosts.length,
      page: parseInt(page),
      limit: parseInt(limit),
      pages: Math.ceil(filteredPosts.length / limit)
    }
  });
});

app.post('/api/posts', (req, res) => {
  const { title, content, authorId } = req.body;
  if (!title || !content || !authorId) {
    return res.status(400).json({ error: 'Title, content, and authorId are required' });
  }

  const author = users.find(u => u.id === authorId);
  if (!author) {
    return res.status(404).json({ error: 'Author not found' });
  }

  const post = {
    id: nextId++,
    title,
    content,
    authorId,
    authorName: author.name,
    createdAt: new Date(),
    updatedAt: new Date()
  };

  posts.push(post);
  res.status(201).json(post);
});

app.get('/api/posts/:id', (req, res) => {
  const post = posts.find(p => p.id === parseInt(req.params.id));
  if (!post) {
    return res.status(404).json({ error: 'Post not found' });
  }

  // Get comments for this post
  const postComments = comments.filter(c => c.postId === post.id);
  res.json({ ...post, comments: postComments });
});

app.put('/api/posts/:id', (req, res) => {
  const postIndex = posts.findIndex(p => p.id === parseInt(req.params.id));
  if (postIndex === -1) {
    return res.status(404).json({ error: 'Post not found' });
  }

  const { title, content } = req.body;
  if (!title || !content) {
    return res.status(400).json({ error: 'Title and content are required' });
  }

  posts[postIndex] = {
    ...posts[postIndex],
    title,
    content,
    updatedAt: new Date()
  };

  res.json(posts[postIndex]);
});

app.delete('/api/posts/:id', (req, res) => {
  const postIndex = posts.findIndex(p => p.id === parseInt(req.params.id));
  if (postIndex === -1) {
    return res.status(404).json({ error: 'Post not found' });
  }

  posts.splice(postIndex, 1);
  res.status(204).send();
});

// Comments routes
app.post('/api/posts/:postId/comments', (req, res) => {
  const post = posts.find(p => p.id === parseInt(req.params.postId));
  if (!post) {
    return res.status(404).json({ error: 'Post not found' });
  }

  const { authorId, content } = req.body;
  if (!authorId || !content) {
    return res.status(400).json({ error: 'AuthorId and content are required' });
  }

  const author = users.find(u => u.id === authorId);
  if (!author) {
    return res.status(404).json({ error: 'Author not found' });
  }

  const comment = {
    id: nextId++,
    postId: post.id,
    authorId,
    authorName: author.name,
    content,
    createdAt: new Date()
  };

  comments.push(comment);
  res.status(201).json(comment);
});

app.listen(3000, () => {
  console.log('Blog API running at http://localhost:3000');
});
